import api from "./axiosInstance";

export default class BaseController {
  static async get(endpoint, config = {}) {
    return this.handleRequest(async () => {
      const { data } = await api.get(endpoint, config);
      return data;
    }, `GET request failed: ${endpoint}`);
  }

  static async getData(endpoint, config = {}) {
    const data = await this.get(endpoint, config);
    return data.data;
  }

  static async post(endpoint, payload = {}, config = {}) {
    return this.handleRequest(async () => {
      const { data } = await api.post(endpoint, payload, config);
      return data;
    }, `POST request failed: ${endpoint}`);
  }

  static async postData(endpoint, payload = {}, config = {}) {
    const data = await this.post(endpoint, payload, config);
    return data.data;
  }

  static async put(endpoint, payload = {}, config = {}) {
    return this.handleRequest(async () => {
      const { data } = await api.put(endpoint, payload, config);
      return data;
    }, `PUT request failed: ${endpoint}`);
  }

  static async putData(endpoint, payload = {}, config = {}) {
    const data = await this.put(endpoint, payload, config);
    return data.data;
  }

  static async delete(endpoint, config = {}) {
    return this.handleRequest(async () => {
      const { data } = await api.delete(endpoint, config);
      return data;
    }, `DELETE request failed: ${endpoint}`);
  }

  static async deleteData(endpoint, config = {}) {
    const data = await this.delete(endpoint, config);
    return data.data;
  }

  static async handleRequest(requestFn, errorMessage) {
    try {
      return requestFn();
    } catch (error) {
      console.error(errorMessage, error);
      throw error;
    }
  }

  static async getItems(endpoint, page = 1, perPage = 20, params = {}) {
    return this.handleRequest(async () => {
      const queryParams = { page, per_page: perPage, ...params };
      const response = await api.get(endpoint, { params: queryParams });
      const payload = response.data.data;
      return {
        items: payload.items,
        current_page: payload.meta.current_page,
        next_page: payload.meta.next_page,
        last_page: payload.meta.last_page,
        per_page: payload.meta.per_page,
        total: payload.meta.total,
      };
    }, `Failed to fetch list: ${endpoint}`);
  }

  static async getItem(endpoint, id) {
    return this.handleRequest(async () => {
      const response = await api.get(`${endpoint}/${id}`);
      return response.data.data;
    }, `Failed to fetch item: ${endpoint}/${id}`);
  }

  static async getListItems(endpoint, params = {}) {
    return this.handleRequest(async () => {
      const response = await api.get(`${endpoint}/all`, { params });
      return response.data.data;
    }, `Failed to fetch all items: ${endpoint}/all`);
  }

  static validateInput(item, requiredFields = []) {
    if (!item || item !== Object(item)) {
      throw new Error("Payload must be an object");
    }

    if (requiredFields.length > 0) {
      const missingFields = requiredFields.filter((field) => {
        const value = item[field];
        return value === null || value === undefined || value === "";
      });

      if (missingFields.length > 0) {
        throw new Error(
          `Required fields are missing: ${missingFields.join(", ")}`
        );
      }
    }

    return true;
  }

  static async storeItem(endpoint, item, options = {}) {
    return this.handleRequest(async () => {
      const {
        file = null,
        fileField = null,
        headers = {},
        requiredFields = [],
      } = options;

      // Базовая валидация входных данных
      this.validateInput(item, requiredFields);

      if (file && fileField) {
        const formData = this.createFormData(item, fileField, file, options);
        const { data } = await api.post(endpoint, formData, {
          headers: {
            "Content-Type": "multipart/form-data",
            ...headers,
          },
        });
        return data;
      } else {
        const { data } = await api.post(endpoint, item, { headers });
        return data;
      }
    }, `Failed to create item: ${endpoint}`);
  }

  static async updateItem(endpoint, id, item, options = {}) {
    return this.handleRequest(async () => {
      const {
        file = null,
        fileField = null,
        headers = {},
        requiredFields = [],
      } = options;

      // Базовая валидация входных данных
      if (!id) {
        throw new Error("ID is required to update item");
      }
      this.validateInput(item, requiredFields);

      if (file && fileField) {
        const formData = this.createFormData(item, fileField, file, options);
        const { data } = await api.put(`${endpoint}/${id}`, formData, {
          headers: {
            "Content-Type": "multipart/form-data",
            ...headers,
          },
        });
        return data;
      } else {
        const { data } = await api.put(`${endpoint}/${id}`, item, { headers });
        return data;
      }
    }, `Failed to update item: ${endpoint}/${id}`);
  }

  static async deleteItem(endpoint, id) {
    return this.handleRequest(async () => {
      if (!id) {
        throw new Error("ID is required to delete item");
      }
      const { data } = await api.delete(`${endpoint}/${id}`);
      return data;
    }, `Failed to delete item: ${endpoint}/${id}`);
  }

  static async downloadExport(endpoint, params = {}, ids = null, defaultFilename = 'export.xlsx') {
    return this.handleRequest(async () => {
      const requestParams = { ...params };
      if (Array.isArray(ids) && ids.length > 0) {
        requestParams.ids = ids;
      }
      const response = await api.get(`${endpoint}/export`, {
        params: requestParams,
        responseType: 'blob',
      });
      const url = window.URL.createObjectURL(new Blob([response.data]));
      const link = document.createElement('a');
      link.href = url;
      const contentDisposition = response.headers['content-disposition'];
      let filename = defaultFilename;
      if (contentDisposition) {
        const filenameMatch = contentDisposition.match(/filename\*?=(?:UTF-8'')?"?([^";\n]+)"?/i)
          || contentDisposition.match(/filename="?([^";\n]+)"?/i);
        if (filenameMatch && filenameMatch[1]) {
          filename = filenameMatch[1].trim().replace(/^["']|["']$/g, '');
        }
      }
      link.setAttribute('download', filename);
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
      return true;
    }, `Export failed: ${endpoint}/export`);
  }

  static createFormData(payload, fileField, file, options = {}) {
    const formData = new FormData();
    const { booleanFields = [] } = options;

    Object.keys(payload).forEach((key) => {
      const value = payload[key];
      if (value === null || value === undefined) {
        return;
      }

      if (Array.isArray(value)) {
        value.forEach((item, index) => {
          formData.append(`${key}[${index}]`, item);
        });
      } else if (booleanFields.includes(key)) {
        formData.append(key, value ? "1" : "0");
      } else if (value && value === Object(value)) {
        // Если значение - объект (например, work_schedule), преобразуем в JSON строку
        formData.append(key, JSON.stringify(value));
      }else {
        formData.append(key, value);
      }
    });

    if (file && fileField) {
      formData.append(fileField, file);
    }

    return formData;
  }
}

import BaseController from "./BaseController";

export default class ChatController extends BaseController {
  static normalizeFile(file) {
    if (!file) return file;
    return {
      ...file,
      mimeType: file.mime_type,
    };
  }

  static normalizeReaction(reaction) {
    if (!reaction) return reaction;
    return {
      ...reaction,
      creatorId: reaction.creator_id,
    };
  }

  static normalizeMessage(message) {
    if (!message) return message;
    return {
      ...message,
      chatId: message.chat_id,
      creatorId: message.creator_id,
      createdAt: message.created_at,
      updatedAt: message.updated_at,
      editedAt: message.edited_at,
      isEdited: message.is_edited,
      parentId: message.parent_id,
      forwardedFrom: message.forwarded_from,
      files: (message.files || []).map((file) => this.normalizeFile(file)),
      reactions: (message.reactions || []).map((reaction) => this.normalizeReaction(reaction)),
    };
  }

  static normalizeChat(chat) {
    if (!chat) return chat;
    return {
      ...chat,
      unreadCount: chat.unread_count,
      lastMessageAt: chat.last_message_at,
      lastMessage: this.normalizeMessage(chat.last_message),
      pinnedMessage: this.normalizeMessage(chat.pinned_message),
      peerLastReadMessageId: chat.peer_last_read_message_id,
      directKey: chat.direct_key,
      createdBy: chat.created_by,
    };
  }

  static async getChats() {
    return super.handleRequest(
      async () => {
        const data = await super.getData("/chats");
        return (data || []).map((chat) => this.normalizeChat(chat));
      },
      "Ошибка при загрузке чатов:"
    );
  }

  static async ensureGeneralChat() {
    return super.handleRequest(
      async () => {
        return super.postData("/chats/general");
      },
      "Ошибка при создании общего чата:"
    );
  }

  static async getMessages(chatId, params = {}) {
    return super.handleRequest(
      async () => {
        const data = await super.getData(`/chats/${chatId}/messages`, { params });
        return (data || []).map((message) => this.normalizeMessage(message));
      },
      "Ошибка при загрузке сообщений:"
    );
  }

  static async searchMessages(chatId, q, params = {}) {
    return super.handleRequest(
      async () => {
        const data = await super.getData(`/chats/${chatId}/messages/search`, { params: { q, ...params } });
        return (data || []).map((message) => this.normalizeMessage(message));
      },
      "Ошибка поиска сообщений:"
    );
  }

  static async markAsRead(chatId, lastMessageId = null) {
    return super.handleRequest(
      async () => {
        const payload = {};
        if (lastMessageId) {
          payload.last_message_id = lastMessageId;
        }
        return super.postData(`/chats/${chatId}/read`, payload);
      },
      "Ошибка при отметке чата как прочитанного:"
    );
  }

  static async sendTyping(chatId) {
    if (!chatId) return { ok: false };
    try {
      await super.post(`/chats/${chatId}/typing`);
      return { ok: true };
    } catch (e) {
      if (e?.response?.status !== 404) {
        console.error('sendTyping:', e?.message || e);
      }
      return { ok: false };
    }
  }

  static async startDirectChat(userId) {
    return super.handleRequest(
      async () => {
        return super.postData("/chats/direct", { creator_id: userId });
      },
      "Ошибка при создании личного чата:"
    );
  }

  static async createGroupChat(payload) {
    return super.handleRequest(
      async () => {
        return super.postData("/chats/groups", payload);
      },
      "Ошибка при создании группового чата:"
    );
  }

  static async sendMessage(chatId, { body = "", files = [], parent_id = null } = {}) {
    return super.handleRequest(
      async () => {
        const formData = new FormData();
        if (body) {
          formData.append("body", body);
        }
        if (parent_id) {
          formData.append("parent_id", parent_id);
        }
        (files || []).forEach((file) => {
          formData.append("files[]", file);
        });

        const data = await super.postData(`/chats/${chatId}/messages`, formData, {
          headers: {
            "Content-Type": "multipart/form-data",
          },
        });
        return this.normalizeMessage(data);
      },
      "Ошибка при отправке сообщения:"
    );
  }

  static async updateMessage(chatId, messageId, body, files = null) {
    return super.handleRequest(
      async () => {
        const payload = { body };
        if (files && Array.isArray(files)) {
          payload.files = files;
        }
        const data = await super.putData(`/chats/${chatId}/messages/${messageId}`, payload);
        return this.normalizeMessage(data);
      },
      "Ошибка при редактировании сообщения:"
    );
  }

  static async deleteMessage(chatId, messageId) {
    return super.handleRequest(
      async () => {
        return super.deleteData(`/chats/${chatId}/messages/${messageId}`);
      },
      "Ошибка при удалении сообщения:"
    );
  }

  static async forwardMessage(chatId, messageId, targetChatId) {
    return super.handleRequest(
      async () => {
        return super.postData(`/chats/${chatId}/messages/${messageId}/forward`, {
          target_chat_id: targetChatId,
        });
      },
      "Ошибка при пересылке сообщения:"
    );
  }

  static async deleteChat(chatId) {
    return super.handleRequest(
      async () => {
        return super.deleteData(`/chats/${chatId}`);
      },
      "Ошибка при удалении чата:"
    );
  }

  static async pinMessage(chatId, messageId) {
    return super.handleRequest(
      async () => {
        const data = await super.postData(`/chats/${chatId}/messages/${messageId}/pin`);
        return {
          ...data,
          chat: this.normalizeChat(data?.chat),
        };
      },
      "Ошибка при закреплении:"
    );
  }

  static async unpinMessage(chatId) {
    return super.handleRequest(
      async () => {
        return super.deleteData(`/chats/${chatId}/pin`);
      },
      "Ошибка при откреплении:"
    );
  }

  static async setReaction(chatId, messageId, emoji) {
    return super.handleRequest(
      async () => {
        const payload = emoji != null && emoji !== "" ? { emoji } : {};
        return super.postData(`/chats/${chatId}/messages/${messageId}/reaction`, payload);
      },
      "Ошибка при установке реакции:"
    );
  }
}

import axios from "axios";
import AuthController from "./AuthController";
import { startApiCall, endApiCall, getStore } from "@/store/storeManager";
import TokenUtils from "@/utils/tokenUtils";

const MAINTENANCE_BYPASS_KEY = "maintenance_bypass";

const baseURL = `${import.meta.env.VITE_APP_BASE_URL || "http://127.0.0.1"}/api`;

const api = axios.create({
  baseURL,
  timeout: 30000,
  headers: {
    "Content-Type": "application/json",
  },
});

export const authApi = axios.create({
  baseURL,
  timeout: 30000,
  headers: {
    "Content-Type": "application/json",
  },
});

export function getMaintenanceBypassKey() {
  return MAINTENANCE_BYPASS_KEY;
}

async function showSessionExpiredNotification() {
  const store = getStore();
  if (!store) {
    return;
  }

  try {
    const i18n = (await import("@/i18n")).default;
    const t = i18n?.global?.t ?? ((key) => key);
    store.dispatch("showNotification", {
      title: t("sessionExpiredTitle"),
      subtitle: t("sessionExpired"),
      isDanger: true,
    });
  } catch (_) {
    store.dispatch("showNotification", {
      title: "Session expired",
      subtitle: "Session has expired. Please sign in again.",
      isDanger: true,
    });
  }
}

api.interceptors.request.use(
  async (config) => {
    startApiCall();

    const bypass = localStorage.getItem(MAINTENANCE_BYPASS_KEY);
    if (bypass) {
      config.headers["X-Maintenance-Bypass"] = bypass;
    }

    const token = TokenUtils.getToken();

    if (token) {
      config.headers.Authorization = `Bearer ${token}`;
    }

    const store = getStore();

    if (store && store.getters.currentCompanyId) {
      config.headers["X-Company-ID"] = store.getters.currentCompanyId;
    } else {
      const defaultCompanyId = import.meta.env.VITE_DEFAULT_COMPANY_ID || "1";
      config.headers["X-Company-ID"] = defaultCompanyId;
    }

    if (config.method === "get" || config.method === "GET") {
      config.headers["Cache-Control"] = "no-cache, no-store, must-revalidate";
      config.headers["Pragma"] = "no-cache";
      config.headers["Expires"] = "0";
    }

    return config;
  },
  (error) => {
    endApiCall();
    return Promise.reject(error);
  }
);

api.interceptors.response.use(
  (response) => {
    endApiCall();
    return response;
  },
  async (error) => {
    endApiCall();

    if (error.code === "ECONNABORTED") {
      const store = getStore();
      if (store) {
        try {
          const i18n = (await import("@/i18n")).default;
          const t = i18n?.global?.t ?? ((key) => key);
          store.dispatch("showNotification", {
            title: t("error"),
            subtitle: t("loadTimeout"),
            isDanger: true,
          });
        } catch (_) {
          store.dispatch("showNotification", {
            title: "Error",
            subtitle: "Load timeout",
            isDanger: true,
          });
        }
      }
      return Promise.reject(error);
    }

    if (error.response?.status === 503) {
      if (window.location.pathname !== "/maintenance") {
        window.location.href = "/maintenance";
      }
      return Promise.reject(error);
    }

    const requestUrl = error.config?.url || "";
    if (requestUrl.endsWith("/user/refresh")) {
      TokenUtils.clearAuthData();
      if (window.location.pathname !== "/auth/login") {
        await showSessionExpiredNotification();
        window.location.href = "/auth/login";
      }
      return Promise.reject(error);
    }

    if (error.response?.status === 401) {
      const refreshToken = TokenUtils.getRefreshToken();
      if (refreshToken) {
        if (!api.refreshPromise) {
          api.refreshPromise = AuthController.refreshToken();
        }
        try {
          await api.refreshPromise;
          error.config.headers.Authorization = `Bearer ${TokenUtils.getToken()}`;
          return api(error.config);
        } catch (_) {
          TokenUtils.clearAuthData();
          if (window.location.pathname !== "/auth/login") {
            await showSessionExpiredNotification();
            window.location.href = "/auth/login?session_revoked=1";
          }
        } finally {
          api.refreshPromise = null;
        }
      }
    }
    return Promise.reject(error);
  }
);

export default api;

import { eventBus } from "@/eventBus";
import { indexedDBStorage } from "./storage";
import { CACHE_CONFIG } from "./config";

const PRESERVED_PREFIXES = ["tableColumns_", "tableSort_", "cashRegisters_"];
const PRESERVED_KEYS = [
  "hasap_references_cache",
  "hasap_vuex_cache",
  "hasap_user_settings",
  "orders_viewMode",
  "projects_viewMode",
  "kanban_column_order_orders",
  "kanban_column_order_projects",
  "ui_transactions_balance_cards_layout",
  "menuItems",
];

export const CACHE_KEY_PREFIXES = CACHE_CONFIG.keyPrefixes;
export const CACHE_PLAIN_KEYS = CACHE_CONFIG.plainKeys;

let isInvalidatingAll = false;

async function invalidateIndexedDBKey(key) {
  try {
    await indexedDBStorage.removeItem(key);
  } catch (error) {
    if (process.env.NODE_ENV !== "production") {
      console.warn(`Failed to invalidate IndexedDB key ${key}:`, error);
    }
  }
}

export class CacheInvalidator {
  static removeKeyAndTimestamp(key, skipRecursionCheck = false) {
    if (!key) {
      return 0;
    }

    let count = 0;
    try {
      if (localStorage.getItem(key)) {
        localStorage.removeItem(key);
        count++;
      }
      const timestampKey = `${key}_timestamp`;
      if (localStorage.getItem(timestampKey)) {
        localStorage.removeItem(timestampKey);
        count++;
      }
    } catch (error) {
      if (
        error.name === "QuotaExceededError" &&
        !skipRecursionCheck &&
        !isInvalidatingAll
      ) {
        if (process.env.NODE_ENV !== "production") {
          console.warn("localStorage quota exceeded, clearing cache");
        }
        isInvalidatingAll = true;
        this.invalidateAll().finally(() => {
          isInvalidatingAll = false;
        });
      }
    }
    return count;
  }

  static async invalidateByType(type, companyId = null) {
    if (!type) {
      return 0;
    }

    const keysToRemove = CACHE_CONFIG.invalidationPatterns[type] || [];
    if (keysToRemove.length === 0) {
      eventBus.emit("cache:invalidate", { type, companyId });
      return 0;
    }

    const allKeys = Object.keys(localStorage);
    let removedCount = 0;
    const indexedDBKeys = new Set();
    const keysToProcess = new Set();

    const shouldIncludeKey = (key) => {
      return companyId === null || key.includes(`_${companyId}`) || key.includes(`_${companyId}_`);
    };

    keysToRemove.forEach((pattern) => {
      if (!pattern) {
        return;
      }

      const isPrefixPattern = pattern.endsWith("_");

      allKeys.forEach((key) => {
        if (PRESERVED_KEYS.includes(key)) {
          return;
        }
        if (PRESERVED_PREFIXES.some((prefix) => key.startsWith(prefix))) {
          return;
        }
        const matches = isPrefixPattern
          ? key.startsWith(pattern)
          : key === pattern || key.startsWith(pattern);

        if (matches && shouldIncludeKey(key)) {
          keysToProcess.add(key);
        }
      });

      if (!isPrefixPattern) {
        keysToProcess.add(pattern);
        if (CACHE_PLAIN_KEYS.includes(pattern)) {
          indexedDBKeys.add(pattern);
        }
      }
    });

    keysToProcess.forEach((key) => {
      removedCount += this.removeKeyAndTimestamp(key);
    });

    await Promise.all(
      Array.from(indexedDBKeys).map((key) => invalidateIndexedDBKey(key))
    );

    eventBus.emit("cache:invalidate", { type, companyId });

    return removedCount;
  }

  static invalidateByCompany(companyId) {
    if (!companyId) {
      return 0;
    }

    let removedCount = 0;

    CACHE_KEY_PREFIXES.forEach((pattern) => {
      const candidate = `${pattern}${companyId}`;
      if (PRESERVED_KEYS.includes(candidate)) {
        return;
      }
      if (PRESERVED_PREFIXES.some((prefix) => `${pattern}${companyId}`.startsWith(prefix))) {
        return;
      }
      removedCount += this.removeKeyAndTimestamp(`${pattern}${companyId}`);
    });

    return removedCount;
  }

  static async invalidateAll() {
    if (isInvalidatingAll) {
      return 0;
    }

    isInvalidatingAll = true;
    try {
      const cacheKeys = this.getCacheKeys();
      let removedCount = 0;
      const indexedDBKeys = new Set();

      cacheKeys.forEach((key) => {
        try {
          if (PRESERVED_KEYS.includes(key)) {
            return;
          }
          if (localStorage.getItem(key)) {
            localStorage.removeItem(key);
            removedCount++;
          }
          const timestampKey = `${key}_timestamp`;
          if (localStorage.getItem(timestampKey)) {
            localStorage.removeItem(timestampKey);
            removedCount++;
          }
          if (CACHE_PLAIN_KEYS.includes(key)) {
            indexedDBKeys.add(key);
          }
        } catch (error) {
          if (
            error.name === "QuotaExceededError" &&
            process.env.NODE_ENV !== "production"
          ) {
            console.warn("localStorage quota exceeded during invalidateAll");
          }
        }
      });

      await Promise.all(
        Array.from(indexedDBKeys).map((key) => invalidateIndexedDBKey(key))
      );

      return removedCount;
    } finally {
      isInvalidatingAll = false;
    }
  }

  static getCacheKeys() {
    try {
      return Object.keys(localStorage).filter((key) => {
        if (PRESERVED_KEYS.includes(key)) {
          return false;
        }
        if (PRESERVED_PREFIXES.some((prefix) => key.startsWith(prefix))) {
          return false;
        }
        if (key.includes("_cache") || key.includes("_timestamp")) {
          return true;
        }
        if (CACHE_KEY_PREFIXES.some((prefix) => key.startsWith(prefix))) {
          return true;
        }
        if (CACHE_PLAIN_KEYS.includes(key)) {
          return true;
        }
        return false;
      });
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.warn("Error getting cache keys:", error);
      }
      return [];
    }
  }

  static async invalidateCrud(type, companyId = null) {
    await this.invalidateByType(type, companyId);
    await this.invalidateDependencies(type, companyId);
  }

  static onCreate(type, companyId = null) {
    return this.invalidateCrud(type, companyId);
  }

  static onUpdate(type, companyId = null) {
    return this.invalidateCrud(type, companyId);
  }

  static onDelete(type, companyId = null) {
    return this.invalidateCrud(type, companyId);
  }

  static async invalidateDependencies(type, companyId = null) {
    if (!type) {
      return;
    }

    const dependentTypes = CACHE_CONFIG.dependencies[type] || [];
    await Promise.all(
      dependentTypes.map((dependentType) =>
        this.invalidateByType(dependentType, companyId)
      )
    );
  }

  static async onCompanyChange(_oldCompanyId, _newCompanyId) {
    return await this.invalidateAll();
  }

  static onUserChange() {
    return this.invalidateAll();
  }
}

export function companyScopedKey(prefix, companyId) {
  if (!prefix) throw new Error("companyScopedKey: prefix is required");
  if (!companyId) throw new Error("companyScopedKey: companyId is required");
  return `${prefix}_${companyId}`;
}

export function timestampKey(key) {
  return `${key}_timestamp`;
}

export function isFreshByKey(key, ttlMs) {
  if (process.env.NODE_ENV !== "production") {
    return false; // Всегда считаем кеш устаревшим в режиме разработки
  }

  if (!key) return false;

  try {
    const tsKey = timestampKey(key);
    const tsStr = localStorage.getItem(tsKey);
    if (!tsStr) return false;
    const ts = parseInt(tsStr, 10);
    if (Number.isNaN(ts)) return false;
    return Date.now() - ts <= ttlMs;
  } catch (error) {
    return false;
  }
}

export function touchKey(key) {
  if (!key) return;

  try {
    localStorage.setItem(timestampKey(key), Date.now().toString());
  } catch (error) {
    if (error.name === "QuotaExceededError" && process.env.NODE_ENV !== "production") {
      console.warn("localStorage quota exceeded in touchKey");
    }
  }
}

export function clearKey(key) {
  if (!key) return;

  try {
    localStorage.removeItem(key);
    localStorage.removeItem(timestampKey(key));
  } catch (error) {
    if (process.env.NODE_ENV !== "production") {
      console.warn("Error clearing key:", error);
    }
  }
}

export function isCompanyCacheFresh(prefix, companyId, ttlMs) {
  try {
    const key = companyScopedKey(prefix, companyId);
    return isFreshByKey(key, ttlMs);
  } catch (error) {
    return false;
  }
}

export function touchCompanyCache(prefix, companyId) {
  try {
    const key = companyScopedKey(prefix, companyId);
    touchKey(key);
  } catch (error) {
    if (process.env.NODE_ENV !== "production") {
      console.warn("Error touching company cache:", error);
    }
  }
}

export function clearCompanyCache(prefix, companyId) {
  try {
    const key = companyScopedKey(prefix, companyId);
    clearKey(key);
  } catch (error) {
    if (process.env.NODE_ENV !== "production") {
      console.warn("Error clearing company cache:", error);
    }
  }
}

import { companyScopedKey, isFreshByKey, touchKey } from "./invalidator";
import { retryWithExponentialBackoff } from "./utils";

export async function loadGlobalReference(
  { commit, state, getters, dispatch },
  {
    cacheKey,
    ttl,
    mutation,
    loadingFlag,
    fetchFn,
    logName,
    transformFn,
    stateKey,
  }
) {
  if (!cacheKey || !mutation || !loadingFlag || !fetchFn) {
    throw new Error("loadGlobalReference: required parameters missing");
  }

  if (state.loadingFlags && state.loadingFlags[loadingFlag]) {
    return dispatch("waitForLoading", loadingFlag);
  }

  if (!isFreshByKey(cacheKey, ttl)) {
    commit(mutation, []);
  }

  const dataKey = stateKey || cacheKey;
  const data = state[dataKey];
  if (Array.isArray(data) && data.length > 0) {
    return;
  }

  commit("SET_LOADING_FLAG", { type: loadingFlag, loading: true });

  try {
    const data = await retryWithExponentialBackoff(fetchFn, 3);
    const finalData = transformFn ? transformFn(data, state) : data;
    commit(mutation, finalData);
    touchKey(cacheKey);
  } catch (error) {
    if (process.env.NODE_ENV !== "production") {
      console.error(`Ошибка загрузки ${logName || "данных"}:`, error);
    }
    commit(mutation, []);
  } finally {
    commit("SET_LOADING_FLAG", { type: loadingFlag, loading: false });
  }
}

export async function loadCompanyScopedData({ commit, state, dispatch }, config) {
  const {
    loadingFlagKey,
    companyId,
    cacheKeyPrefix,
    cacheTtl,
    clearMutations,
    loggedFlagKey,
    logEmoji,
    logName,
    fetchData,
    errorName,
    stateKey,
    onError,
  } = config;

  if (!loadingFlagKey || !cacheKeyPrefix || !stateKey || !fetchData) {
    throw new Error("loadCompanyScopedData: required parameters missing");
  }
  if (!Array.isArray(clearMutations) || clearMutations.length === 0) {
    throw new Error("loadCompanyScopedData: clearMutations must be a non-empty array");
  }

  if (state.loadingFlags && state.loadingFlags[loadingFlagKey]) {
    return dispatch("waitForLoading", loadingFlagKey);
  }

  if (!companyId) {
    clearMutations.forEach((mutation) => commit(mutation, []));
    return;
  }

  const cacheKey = companyScopedKey(cacheKeyPrefix, companyId);
  const ttl = cacheTtl;

  if (!isFreshByKey(cacheKey, ttl)) {
    clearMutations.forEach((mutation) => commit(mutation, []));
  }

  const stateData = state[stateKey];

  if (Array.isArray(stateData) && stateData.length > 0 && isFreshByKey(cacheKey, ttl)) {
    if (loggedFlagKey && state.loggedDataFlags && !state.loggedDataFlags[loggedFlagKey]) {
      commit("SET_LOGGED_DATA_FLAG", { type: loggedFlagKey, logged: true });
    }
    return;
  }

  commit("SET_LOADING_FLAG", { type: loadingFlagKey, loading: true });

  try {
    const data = await retryWithExponentialBackoff(fetchData, 3);
    commit(clearMutations[0], data);
    if (clearMutations.length > 1) {
      clearMutations.slice(1).forEach((mutation) => {
        commit(mutation, data);
      });
    }
    touchKey(cacheKey);
  } catch (error) {
    clearMutations.forEach((mutation) => commit(mutation, []));
    if (onError) {
      onError(dispatch, errorName, error);
    } else {
      if (process.env.NODE_ENV !== "production") {
        console.error(`❌ Ошибка загрузки ${errorName || "данных"}:`, error);
      }
      dispatch("showNotification", {
        title: `Ошибка загрузки ${errorName || "данных"}`,
        subtitle: error.message,
        isDanger: true,
      });
    }
  } finally {
    commit("SET_LOADING_FLAG", { type: loadingFlagKey, loading: false });
  }
}

export async function restoreDtoFromPlainData({
  commit,
  state,
  plainDataKey,
  dtoKey,
  dtoClassPath,
  dtoMutation,
  plainDataMutation,
  cacheKey,
  ttl,
  companyId = null,
  validateFn = null,
}) {
  if (!plainDataKey || !dtoKey || !dtoClassPath || !cacheKey) {
    throw new Error("restoreDtoFromPlainData: required parameters missing");
  }

  const plainData = state[plainDataKey];
  const dtoData = state[dtoKey];

  if (
    Array.isArray(plainData) &&
    plainData.length > 0 &&
    Array.isArray(dtoData) &&
    dtoData.length === 0 &&
    isFreshByKey(cacheKey, ttl)
  ) {
    if (validateFn && !validateFn(plainData)) {
      if (plainDataMutation) commit(plainDataMutation, []);
      if (dtoMutation) commit(dtoMutation, []);
      return false;
    }

    try {
      const DtoClass = (await import(dtoClassPath)).default;
      if (!DtoClass?.fromApiArray) {
        return false;
      }
      const restored = DtoClass.fromApiArray(plainData);
      if (dtoMutation) commit(dtoMutation, restored);
      return true;
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.error("Error restoring DTO from plain data:", error);
      }
      return false;
    }
  }

  return false;
}

import { CACHE_CONFIG } from "./config";

let db = null;
let dbOpenPromise = null;
const DB_NAME = CACHE_CONFIG.indexedDB.dbName;
const DB_VERSION = CACHE_CONFIG.indexedDB.dbVersion;
const STORE_NAME = CACHE_CONFIG.indexedDB.storeName;

function openDB() {
  if (db && db.objectStoreNames.contains(STORE_NAME)) {
    return Promise.resolve(db);
  }

  if (dbOpenPromise) {
    return dbOpenPromise;
  }

  dbOpenPromise = new Promise((resolve, reject) => {
    if (!window.indexedDB) {
      reject(new Error("IndexedDB is not supported"));
      return;
    }

    const request = indexedDB.open(DB_NAME, DB_VERSION);
    let upgradeBlocked = false;

    request.onerror = () => {
      dbOpenPromise = null;
      reject(request.error);
    };

    request.onsuccess = () => {
      db = request.result;
      db.onclose = () => {
        db = null;
        dbOpenPromise = null;
      };
      db.onerror = () => {
        db = null;
        dbOpenPromise = null;
      };
      resolve(db);
    };

    request.onupgradeneeded = (event) => {
      const database = event.target.result;
      if (!database.objectStoreNames.contains(STORE_NAME)) {
        database.createObjectStore(STORE_NAME);
      }
    };

    request.onblocked = () => {
      upgradeBlocked = true;
      if (process.env.NODE_ENV !== "production") {
        console.warn("IndexedDB upgrade blocked by other tabs. Please close other tabs and refresh.");
      }

      const checkInterval = setInterval(() => {
        if (!upgradeBlocked) {
          clearInterval(checkInterval);
          return;
        }

        const retryRequest = indexedDB.open(DB_NAME, DB_VERSION);
        retryRequest.onsuccess = () => {
          clearInterval(checkInterval);
          db = retryRequest.result;
          dbOpenPromise = Promise.resolve(db);
          resolve(db);
        };
        retryRequest.onerror = () => {
          clearInterval(checkInterval);
          reject(retryRequest.error);
        };
      }, 1000);
    };
  });

  return dbOpenPromise;
}

export const indexedDBStorage = {
  async getItem(key) {
    if (!key) {
      return null;
    }

    try {
      const database = await openDB();
      return new Promise((resolve, reject) => {
        const transaction = database.transaction([STORE_NAME], "readonly");
        const store = transaction.objectStore(STORE_NAME);
        const request = store.get(key);

        request.onerror = () => reject(request.error);
        request.onsuccess = () => {
          const result = request.result;
          resolve(result ? JSON.stringify(result) : null);
        };
      });
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.warn("IndexedDB getItem error:", error);
      }
      return null;
    }
  },

  async setItem(key, value) {
    if (!key) {
      throw new Error("setItem: key is required");
    }

    try {
      const database = await openDB();
      return new Promise((resolve, reject) => {
        const transaction = database.transaction([STORE_NAME], "readwrite");
        const store = transaction.objectStore(STORE_NAME);

        let parsedValue;
        try {
          parsedValue = JSON.parse(value);
        } catch (parseError) {
          reject(
            new Error(
              `Failed to parse value for key ${key}: ${parseError.message}`
            )
          );
          return;
        }

        const request = store.put(parsedValue, key);

        transaction.onerror = () => {
          const error = transaction.error || request.error;
          reject(error || new Error("Transaction failed"));
        };

        transaction.onabort = () => {
          reject(new Error("Transaction aborted"));
        };

        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve();
      });
    } catch (error) {
      if (error.name === "QuotaExceededError") {
        if (process.env.NODE_ENV !== "production") {
          console.error("IndexedDB quota exceeded for key:", key);
        }
        throw new Error("Storage quota exceeded. Please clear some data.");
      }
      if (process.env.NODE_ENV !== "production") {
        console.warn("IndexedDB setItem error:", error);
      }
      throw error;
    }
  },

  async removeItem(key) {
    if (!key) {
      return;
    }

    try {
      const database = await openDB();
      return new Promise((resolve, reject) => {
        const transaction = database.transaction([STORE_NAME], "readwrite");
        const store = transaction.objectStore(STORE_NAME);
        const request = store.delete(key);

        transaction.onerror = () => {
          const error = transaction.error || request.error;
          reject(error || new Error("Transaction failed"));
        };

        request.onerror = () => reject(request.error);
        request.onsuccess = () => resolve();
      });
    } catch (error) {
      if (process.env.NODE_ENV !== "production") {
        console.warn("IndexedDB removeItem error:", error);
      }
      throw error;
    }
  },
};

export async function retryWithExponentialBackoff(
  fn,
  maxRetries = 3,
  initialDelay = 1000
) {
  if (!fn) {
    throw new Error("retryWithExponentialBackoff: fn must be a function");
  }

  let lastError;
  for (let attempt = 0; attempt <= maxRetries; attempt++) {
    try {
      return await fn();
    } catch (error) {
      lastError = error;
      if (attempt < maxRetries) {
        const baseDelay = initialDelay * Math.pow(2, attempt);
        const jitter = Math.random() * 0.3 * baseDelay;
        const delay = Math.floor(baseDelay + jitter);
        if (process.env.NODE_ENV !== "production") {
          console.warn(
            `⚠️ Попытка ${attempt + 1} не удалась, повторяю через ${delay}ms...`
          );
        }
        await new Promise((resolve) => setTimeout(resolve, delay));
      }
    }
  }
  throw lastError;
}

export function assertStorageAvailable(storage, cacheKeysToClear = [], testKey = "__vuex_test__") {
  if (!storage || !storage.setItem || !storage.removeItem) {
    return false;
  }

  try {
    storage.setItem(testKey, testKey);
    storage.removeItem(testKey);
    return true;
  } catch (e) {
    if (cacheKeysToClear.length > 0) {
      if (process.env.NODE_ENV !== "production") {
        console.warn("Storage quota exceeded, clearing old cache");
      }
      try {
        cacheKeysToClear.forEach((key) => storage.removeItem(key));
        try {
          storage.setItem(testKey, testKey);
          storage.removeItem(testKey);
          return true;
        } catch {
          return false;
        }
      } catch {
        return false;
      }
    }
    return false;
  }
}

import ClientPhoneDto from "./ClientPhoneDto";
import { formatNumber } from "@/utils/numberUtils";
