  formatCreatedAt() {
    return dtoDateFormatters.formatCreatedAt(this.createdAt);
  }

  formatUpdatedAt() {
    return dtoDateFormatters.formatUpdatedAt(this.updatedAt);
  }

  getPaymentStatusText() {
    if (this.paymentStatusText) {
      return this.paymentStatusText;
    }

    if (this.paymentStatus) {
      switch (this.paymentStatus) {
        case 'unpaid':
          return 'Не оплачено';
        case 'partially_paid':
          return 'Частично оплачено';
        case 'paid':
          return 'Оплачено';
        default:
          return 'Не оплачено';
      }
    }

    const paidAmount = parseFloat(this.paidAmount || 0);
    const totalPrice = parseFloat(this.totalPrice || 0);

    if (paidAmount <= 0) {
      return 'Не оплачено';
    } else if (paidAmount < totalPrice) {
      return 'Частично оплачено';
    } else {
      return 'Оплачено';
    }
  }

  getPaymentStatusClass() {
    if (this.paymentStatus) {
      switch (this.paymentStatus) {
        case 'unpaid':
          return 'text-red-600';
        case 'partially_paid':
          return 'text-yellow-600';
        case 'paid':
          return 'text-green-600';
        default:
          return 'text-gray-600';
      }
    }

    const paidAmount = parseFloat(this.paidAmount || 0);
    const totalPrice = parseFloat(this.totalPrice || 0);

    if (paidAmount <= 0) {
      return 'text-red-600';
    } else if (paidAmount < totalPrice) {
      return 'text-yellow-600';
    } else {
      return 'text-green-600';
    }
  }

  getPaymentStatusIcon() {
    if (this.paymentStatus) {
      switch (this.paymentStatus) {
        case 'unpaid':
          return 'fas fa-times-circle';
        case 'partially_paid':
          return 'fas fa-exclamation-circle';
        case 'paid':
          return 'fas fa-check-circle';
        default:
          return 'fas fa-question-circle';
      }
    }

    const paidAmount = parseFloat(this.paidAmount || 0);
    const totalPrice = parseFloat(this.totalPrice || 0);

    if (paidAmount <= 0) {
      return 'fas fa-times-circle';
    } else if (paidAmount < totalPrice) {
      return 'fas fa-exclamation-circle';
    } else {
      return 'fas fa-check-circle';
    }
  }

  static fromApi(data) {
    if (!data) return null;
    const client = data.client ? ClientDto.fromApi(data.client) : null;
    const products = data.products ? OrderProductDto.fromApiArray(data.products) : null;
    const status = data.status || {};
