export default class TaskDto {
  constructor(
    id,
    title,
    description = null,
    statusId = null,
    status = null,
    deadline = null,
    creatorId = null,
    creator = null,
    supervisorId = null,
    supervisor = null,
    executorId = null,
    executor = null,
    projectId = null,
    project = null,
    companyId = null,
    priority = 'low',        
    complexity = 'normal',   
    files = [],
    comments = [],
    checklist = [],
    createdAt = "",
    updatedAt = "",
  ) {
    this.id = id;
    this.title = title;
    this.description = description;
    this.statusId = statusId;
    this.status = status;
    this.deadline = deadline;
    this.creatorId = creatorId;
    this.creator = creator;
    this.supervisorId = supervisorId;
    this.supervisor = supervisor;
    this.executorId = executorId;
    this.executor = executor;
    this.projectId = projectId;
    this.project = project;
    this.companyId = companyId;
    this.priority = priority;
    this.complexity = complexity;
    this.files = files;
    this.comments = comments;
    this.createdAt = createdAt;
    this.updatedAt = updatedAt;
    this.checklist = checklist;
  }

  getPriorityIcons() {
    const icons = {
      'low': '🔥',
      'normal': '🔥🔥',
      'high': '🔥🔥🔥'
    };
    return icons[this.priority] || icons['low'];
  }

  getPriorityLabel() {
    const labels = {
      'low': 'низкий',
      'normal': 'нормальный',
      'high': 'высокий'
    };
    return labels[this.priority] || labels['low'];
  }

  getComplexityIcons() {
    const icons = {
      'simple': '🧠',
      'normal': '🧠🧠',
      'complex': '🧠🧠🧠'
    };
    return icons[this.complexity] || icons['normal'];
  }

  getComplexityLabel() {
    const labels = {
      'simple': 'простая',
      'normal': 'нормальная',
      'complex': 'сложная'
    };
    return labels[this.complexity] || labels['normal'];
  }

  formatDeadline() {
    if (!this.deadline) return '';
    return dtoDateFormatters.formatDate(this.deadline);
  }

  formatCreatedAt() {
    return dtoDateFormatters.formatCreatedAt(this.createdAt);
  }

  formatUpdatedAt() {
    return dtoDateFormatters.formatUpdatedAt(this.updatedAt);
  }

  getStatusBadge() {
    if (this.status && this.status.name) {
      const color = this.status.color || '#6c757d';
      return {
        class: '',
        text: this.status.name,
        color: color,
        style: `background-color: ${color}20; color: ${color}; border-color: ${color};`
      };
    }
    return { class: '', text: '-' };
  }

  getFileUrl(file) {
    return file?.path ? `/storage/${file.path}` : "#";
  }

  getFileIcon(file) {
    const ext = (file?.name || file?.path || "").split(".").pop().toLowerCase();
    if (["pdf"].includes(ext)) return "far fa-file-pdf";
    if (["doc", "docx"].includes(ext)) return "far fa-file-word";
    if (["xls", "xlsx"].includes(ext)) return "far fa-file-excel";
    if (["png", "jpg", "jpeg", "gif", "bmp", "svg"].includes(ext))
      return "far fa-file-image";
    if (["zip", "rar", "7z"].includes(ext)) return "far fa-file-archive";
    if (["txt", "md"].includes(ext)) return "far fa-file-alt";
    return "far fa-file";
  }

  getFormattedFiles() {
    return (this.files || []).map((file) => ({
      name: file.name || file.path,
      url: this.getFileUrl(file),
      icon: this.getFileIcon(file),
      path: file.path,
      size: file.size,
      mimeType: file.mime_type,
      uploadedAt: file.uploaded_at,
      formattedSize: this.formatFileSize(file.size),
      formattedUploadDate: file.uploaded_at ? dtoDateFormatters.formatCreatedAt(file.uploaded_at) : ''
    }));
  }

  formatFileSize(bytes) {
    if (!bytes) return '';
    const sizes = ['Bytes', 'KB', 'MB', 'GB'];
    if (bytes === 0) return '0 Bytes';
    const i = Math.floor(Math.log(bytes) / Math.log(1024));
    return Math.round(bytes / Math.pow(1024, i) * 100) / 100 + ' ' + sizes[i];
  }

  hasFiles() {
    return this.files && this.files.length > 0;
  }

  getFilesCount() {
    return this.files ? this.files.length : 0;
  }

  static fromApi(data) {
    if (!data) return null;
    let checklist = [];
    if (data.checklist) {
      if (!Array.isArray(data.checklist)) {
        try {
          checklist = JSON.parse(String(data.checklist));
        } catch (e) {
          console.error('Error parsing checklist:', e);
          checklist = [];
        }
      } else if (Array.isArray(data.checklist)) {
        checklist = data.checklist;
      }
    }

    return new TaskDto(
      data.id,
      data.title,
      data.description,
      data.status_id || null,
      data.status || null,
      data.deadline,
      data.creator?.id || null,
      data.creator || null,
      data.supervisor?.id || null,
      data.supervisor || null,
      data.executor?.id || null,
      data.executor || null,
      data.project?.id || null,
      data.project || null,
      data.company_id || null,
      data.priority || 'low',
      data.complexity || 'normal',
      data.files || [],
      data.comments || [],
      checklist,
      data.created_at,
      data.updated_at
    );
  }

  static fromApiArray(dataArray) {
    return createFromApiArray(dataArray, TaskDto.fromApi).filter(Boolean);
  }
}

