export default {
    data() {
        return {
            cardFields: []
        };
    },
    mounted() {
        this.loadCardFields();
    },
    methods: {
        getCardFieldsStorageKey() {
            return `cardFields_${this.cardFieldsKey}`;
        },
        getCardFieldsLegacyStorageKey() {
            const companyId = this.$store.state.currentCompany?.id || 'default';
            return `cardFields_${this.cardFieldsKey}_${companyId}`;
        },
        getCardFieldsStorageItem(primaryKey, legacyKey) {
            const saved = localStorage.getItem(primaryKey);
            if (saved) return saved;
            const legacy = legacyKey ? localStorage.getItem(legacyKey) : null;
            if (!legacy) return null;
            localStorage.setItem(primaryKey, legacy);
            if (legacyKey) localStorage.removeItem(legacyKey);
            return legacy;
        },
        setCardFieldsStorageItem(primaryKey, legacyKey, value) {
            localStorage.setItem(primaryKey, value);
            if (legacyKey) localStorage.removeItem(legacyKey);
        },
        loadCardFields() {
            const base = this.cardConfigBase || [];
            const toggleableFields = base.filter(f => f.name && f.name !== (this.titleField || 'title'));
            const saved = this.getCardFieldsStorageItem(
                this.getCardFieldsStorageKey(),
                this.getCardFieldsLegacyStorageKey()
            );
            if (saved) {
                try {
                    const savedMap = JSON.parse(saved);
                    this.cardFields = toggleableFields.map(f => {
                        const stored = savedMap[f.name];
                        return {
                            ...f,
                            visible: stored !== undefined ? stored : true
                        };
                    });
                } catch (e) {
                    this.resetCardFields();
                }
            } else {
                this.cardFields = toggleableFields.map(f => ({
                    ...f,
                    visible: f.visible !== undefined && !f.visible?.call ? f.visible : true
                }));
            }
        },
        saveCardFields() {
            const map = {};
            this.cardFields.forEach(f => { map[f.name] = f.visible; });
            this.setCardFieldsStorageItem(
                this.getCardFieldsStorageKey(),
                this.getCardFieldsLegacyStorageKey(),
                JSON.stringify(map)
            );
        },
        toggleCardFieldVisible(index) {
            if (index < 0 || index >= this.cardFields.length) return;
            this.cardFields[index].visible = !this.cardFields[index].visible;
            this.saveCardFields();
        },
        resetCardFields() {
            const base = this.cardConfigBase || [];
            const toggleableFields = base.filter(f => f.name && f.name !== (this.titleField || 'title'));
            this.cardFields = toggleableFields.map(f => ({
                ...f,
                visible: f.visible !== undefined && !f.visible?.call ? f.visible : true
            }));
            this.saveCardFields();
        }
    }
};

import { eventBus } from '@/eventBus';

export default {
  data() {
    return {
      _companyChangeProcessing: false,
      _lastProcessedCompanyId: null,
      _boundOnCompanyChanged: null
    };
  },

  computed: {
    currentCompanyId() {
      return this.$store.getters.currentCompanyId;
    }
  },

  watch: {
    currentCompanyId: {
      handler(newCompanyId, oldCompanyId) {
        if (newCompanyId && newCompanyId !== oldCompanyId && newCompanyId !== this._lastProcessedCompanyId) {
          this.onCompanyChanged(newCompanyId, oldCompanyId);
        }
      },
      immediate: false
    }
  },

  mounted() {
    this._boundOnCompanyChanged = (companyId) => this.onCompanyChanged(companyId, undefined);
    eventBus.on('company-changed', this._boundOnCompanyChanged);
    this._lastProcessedCompanyId = this.currentCompanyId;
  },

  beforeUnmount() {
    this._isDestroyed = true;
    if (this._boundOnCompanyChanged) {
      eventBus.off('company-changed', this._boundOnCompanyChanged);
    }
  },

  methods: {
    async onCompanyChanged(companyId, previousCompanyId) {
      if (this._isDestroyed) return;
      if (!companyId) return;

      if (this._companyChangeProcessing) {
        return;
      }

      if (companyId === this._lastProcessedCompanyId) {
        return;
      }

      this._companyChangeProcessing = true;
      const isInitialLoad = arguments.length === 2 && previousCompanyId == null;

      try {
        this._lastProcessedCompanyId = companyId;
        if (this.handleCompanyChanged) {
          await this.handleCompanyChanged(companyId, previousCompanyId);
        } else if (this.fetchItems) {
          await this.fetchItems(1, previousCompanyId == null);
        } else if (this.refreshData) {
          await this.refreshData();
        }
      } catch (error) {
        console.error('Ошибка при обработке смены компании:', error);
      } finally {
        this._companyChangeProcessing = false;
      }
    }
  }
};

import { CacheInvalidator } from "@/cache";

export default {
  data() {
    let perPage = 20;
    try {
      const savedPerPage = localStorage.getItem("perPage");
      if (savedPerPage) {
        const parsed = parseInt(savedPerPage, 10);
        if (!isNaN(parsed) && parsed > 0 && parsed <= 50) {
          perPage = parsed;
        } else if (parsed > 50) {
          localStorage.removeItem("perPage");
        }
      }
    } catch (e) {
      console.warn("localStorage is unavailable:", e);
    }

    return {
      data: null,
      loading: false,
      perPage: perPage,
      perPageOptions: [20, 50],
    };
  },
  watch: {
    perPage(newValue) {
      if (newValue > 50) {
        return;
      }
      try {
        localStorage.setItem("perPage", newValue.toString());
      } catch (e) {
        console.warn("Failed to persist perPage:", e);
      }
    },
  },
  methods: {
    invalidateCache(action) {
      if (this.cacheInvalidationType && CacheInvalidator[action]) {
        const companyId = this.$store.state.currentCompany?.id;
        CacheInvalidator[action]?.(this.cacheInvalidationType, companyId);
      }
    },
    refreshDataAfterOperation() {
      if (this.fetchItems) {
        this.fetchItems(this.data?.currentPage || 1, true)
          .then(() => this.restoreScrollPosition?.())
          .catch((error) => console.error("Failed to refresh data:", error));
      }
      if (this.closeModal) {
        this.shouldRestoreScrollOnClose = false;
        this.closeModal(true);
      }
    },
    handleSaved() {
      this.showNotification(
        this.savedSuccessText || "Saved successfully",
        "",
        false
      );

      this.invalidateCache("onUpdate");
      this.refreshDataAfterOperation();

      if (this.onAfterSaved) {
        this.onAfterSaved();
      }
    },
    handleSavedError(m) {
      const readOnlyMessageSource = m || null;
      const readOnlyMessages = [
        this.$t?.("transactionReadonlyDueToSource"),
        this.$t?.("transactionDeletedReadonly"),
      ].filter(Boolean);

      if (readOnlyMessageSource && readOnlyMessages.includes(readOnlyMessageSource)) {
        this.showNotification(
          this.$t?.("warning") || this.savedErrorText || "Error",
          readOnlyMessageSource,
          { isDanger: false, isInfo: true }
        );
        return;
      }

      let messages = this.getApiErrorMessage(m);
      if (Array.isArray(messages) && messages.length === 0) {
        messages = null;
      }
      if (!messages) {
        messages = ["Save failed"];
      } else if (!Array.isArray(messages)) {
        messages = [messages];
      }
      this.showNotification(
        this.savedErrorText || "Save failed",
        messages,
        true
      );
    },
    handleDeleted() {
      this.showNotification(
        this.deletedSuccessText || "Deleted successfully",
        "",
        false
      );

      this.invalidateCache("onDelete");
      this.refreshDataAfterOperation();

      if (this.onAfterDeleted) {
        this.onAfterDeleted();
      }
    },
    handleDeletedError(m) {
      let messages = this.getApiErrorMessage(m);
      if (Array.isArray(messages) && messages.length === 0) {
        messages = null;
      }
      if (!messages) {
        messages = ["Delete failed"];
      } else if (!Array.isArray(messages)) {
        messages = [messages];
      }
      this.showNotification(
        this.deletedErrorText || "Delete failed",
        messages,
        true
      );
    },
  },
};

