export default {
  data() {
    return {
      initialFormState: null,
      closeConfirmDialog: false,
      isFormInitialized: false,
    };
  },
  mounted() {
    this.$nextTick(() => {
      this.saveInitialState();
    });
  },
  methods: {
    saveInitialState() {
      const state = this.getFormState();
      this.initialFormState = state;
      this.isFormInitialized = state !== null && state === Object(state);
    },
    getFormState() {
      return null;
    },
    checkForChanges() {
      if (!this.isFormInitialized || !this.initialFormState) return false;

      try {
        const currentState = this.getFormState();
        if (!currentState || !this.initialFormState) return false;
        return JSON.stringify(currentState) !== JSON.stringify(this.initialFormState);
      } catch (error) {
        console.error('Error checking form changes:', error);
        return false;
      }
    },
    handleCloseRequest() {
      if (this.uploading) {
        return;
      }

      if (this.checkForChanges()) {
        this.closeConfirmDialog = true;
      } else {
        this.closeForm();
      }
    },
    confirmClose() {
      this.closeConfirmDialog = false;
      this.closeForm();
    },
    cancelClose() {
      this.closeConfirmDialog = false;
    },
    handleEscapeKey() {
      this.handleCloseRequest();
    },
    closeForm() {
      this.$emit('close-request');
    },
    resetFormChanges() {
      this.saveInitialState();
    },
    resetFormInitialization() {
      this.isFormInitialized = false;
    },
  },
};

export default {
  data() {
    return {
      modalDialog: false,
      editingItem: null,
      showTimeline: false,
      savedScrollPosition: 0,
      shouldRestoreScrollOnClose: true,
    };
  },
  methods: {
    showModal(item = null) {
      this.savedScrollPosition =
        window.pageYOffset ?? document.documentElement.scrollTop;
      this.shouldRestoreScrollOnClose = true;
      this.modalDialog = true;
      this.showTimeline = true;
      this.editingItem = item;
    },
    closeModal(skipScrollRestore = false) {
      this.modalDialog = false;
      if (!skipScrollRestore && this.shouldRestoreScrollOnClose) {
        this.$nextTick(() => {
          requestAnimationFrame(() => {
            window.scrollTo({
              top: this.savedScrollPosition,
              behavior: "instant",
            });
          });
        });
      }
    },
    handleModalClose() {
      const formRef = Object.values(this.$refs || {}).find(
        (ref) => ref?.handleCloseRequest
      );
      if (formRef?.handleCloseRequest) {
        formRef.handleCloseRequest();
      } else {
        this.closeModal();
      }
    },
    restoreScrollPosition() {
      this.$nextTick(() => {
        requestAnimationFrame(() => {
          window.scrollTo({
            top: this.savedScrollPosition,
            behavior: "instant",
          });
        });
      });
    },
    onItemClick(item) {
      if (!item?.id) {
        return;
      }
      const routeName = this.itemViewRouteName;
      if (!routeName) {
        console.warn("itemViewRouteName is not defined in component");
        return;
      }

      if (this.$route.name === routeName && this.$route.params.id == item.id) {
        this.showModal(item);
        return;
      }

      const baseRouteName = this.baseRouteName || (routeName ? routeName.replace("View", "") : null);
      if (this.$route.name === baseRouteName || this.$route.name === routeName) {
        this.showModal(item);
        this.$router.push({ name: routeName, params: { id: item.id } }).catch(() => {});
        return;
      }

      this.$router.push({ name: routeName, params: { id: item.id } });
    },
    async handleRouteItem(id) {
      if (!id) {
        if (this.modalDialog) {
          this.closeModal();
        }
        this.editingItem = null;
        return;
      }
      const itemId = Number(id);
      if (!itemId) {
        const baseRouteName =
          this.baseRouteName ||
          (this.itemViewRouteName
            ? this.itemViewRouteName.replace("View", "")
            : null);
        if (baseRouteName) {
          this.$router.replace({ name: baseRouteName });
        }
        return;
      }
      if (this.editingItem?.id === itemId && this.modalDialog) {
        return;
      }
      if (!this.controller) {
        console.warn("controller is not defined in component");
        return;
      }
      try {
        const item = await this.controller.getItem(itemId);
        if (!item) {
          const errorText =
            this.errorGettingItemText ||
            this.$t("errorGettingItem");
          const notFoundText = this.$t("notFound");
          if (this.showNotification) {
            this.showNotification(errorText, notFoundText, true);
          }
          const baseRouteName =
            this.baseRouteName ||
            (this.itemViewRouteName
              ? this.itemViewRouteName.replace("View", "")
              : null);
          if (baseRouteName) {
            this.$router.replace({ name: baseRouteName });
          }
          return;
        }
        this.beforeShowModal?.(item);
        this.showModal(item);
      } catch (error) {
        const errorText =
          this.errorGettingItemText ||
          this.$t("errorGettingItem");
        if (this.showNotification) {
          this.showNotification(errorText, error.message, true);
        }
        const baseRouteName =
          this.baseRouteName ||
          (this.itemViewRouteName
            ? this.itemViewRouteName.replace("View", "")
            : null);
        if (baseRouteName) {
          this.$router.replace({ name: baseRouteName });
        }
      }
    },
  },
};

import { InvoicePdfGenerator } from "@/utils/pdfUtils";
import { getCurrentServerDateObject } from "@/utils/dateUtils";
import pdfMake from 'pdfmake/build/pdfmake';
import pdfFonts from 'pdfmake/build/vfs_fonts';

export default {
    methods: {
        async printInvoiceFromOrders(selectedOrders, variants) {
            if (!variants?.length || !selectedOrders?.length) {
                this.showNotification(this.$t('error'), this.$t('selectPdfVariant'), true);
                return;
            }

            try {
                const allProducts = [];
                let totalAmount = 0;
                const client = selectedOrders[0]?.client;

                if (!client) {
                    this.showNotification(this.$t('error'), this.$t('clientNotFoundInOrder'), true);
                    return;
                }

                selectedOrders.forEach(order => {
                    order.products?.forEach(product => {
                        const quantity = parseFloat(product.quantity || 0);
                        const price = parseFloat(product.price || 0);
                        const totalPrice = quantity * price;
                        totalAmount += totalPrice;

                        allProducts.push({
                            productId: product.productId || product.id,
                            productName: product.productName || product.name,
                            productDescription: product.productDescription ,
                            quantity,
                            price,
                            totalPrice,
                            unitId: product.unitId,
                            unitName: product.unitShortName ,
                            getUnitName() {
                                return this.unitName ;
                            }
                        });
                    });
                });

                const invoiceData = {
                    id: null,
                    invoiceDate: getCurrentServerDateObject().toISOString(),
                    client: client,
                    orders: selectedOrders,
                    products: allProducts,
                    totalAmount: totalAmount,
                    note: '',
                    status: 'new'
                };

                pdfMake.vfs = pdfFonts?.pdfMake?.vfs || pdfFonts?.vfs || {};

                const defaultCompanyData = {
                    name: 'LEBIZLI TURKMEN',
                    address: 'Aşgabat şäheri, Berkararlyk etraby, 2127 (G. Gulyýew) köçesi, 26A H/H',
                    tax_id: '23202934173861407785000',
                    warehouse_id: '23202000173861807785000',
                    email: 'lebizliturkmen@mail.ru',
                    phone: '+993 12 45-26-17'
                };

                variants.forEach(variant => {
                    const generator = new InvoicePdfGenerator(invoiceData, defaultCompanyData, variant);
                    const documentDefinition = generator.generateDocument();
                    const pdfDoc = pdfMake.createPdf(documentDefinition);

                    pdfDoc.getBlob((blob) => {
                        const url = URL.createObjectURL(blob);
                        const iframe = document.createElement('iframe');
                        iframe.style.cssText = 'position:fixed;right:0;bottom:0;width:0;height:0;border:none';
                        iframe.src = url;
                        document.body.appendChild(iframe);

                        const cleanup = () => {
                            if (iframe.parentNode) {
                                iframe.parentNode.removeChild(iframe);
                            }
                            URL.revokeObjectURL(url);
                        };

                        iframe.onload = () => {
                            setTimeout(() => {
                                const printWindow = iframe.contentWindow;
                                const handleAfterPrint = () => {
                                    setTimeout(cleanup, 500);
                                    printWindow.removeEventListener('afterprint', handleAfterPrint);
                                    window.removeEventListener('afterprint', handleAfterPrint);
                                };

                                printWindow.addEventListener('afterprint', handleAfterPrint);
                                window.addEventListener('afterprint', handleAfterPrint);
                                printWindow.print();
                            }, 300);
                        };

                        iframe.onerror = () => {
                            cleanup();
                            this.showNotification(this.$t('error'), this.$t('errorGeneratingPdf'), true);
                        };
                    });
                });

                this.showNotification(this.$t('pdfGenerated'), '', false);
            } catch (error) {
                console.error('Ошибка в printInvoiceFromOrders:', error);
                this.showNotification(this.$t('error'), this.$t('errorGeneratingPdf'), true);
            }
        }
    }
};

export default {
  methods: {

    async loadStoreData(config) {
      if (!config || !config.getterName || !config.dispatchName) {
        console.warn('storeDataLoaderMixin: loadStoreData requires getterName and dispatchName');
        return config?.defaultValue || [];
      }

      const {
        getterName,
        dispatchName,
        localProperty,
        transform,
        onLoaded,
        forceReload = false,
        defaultValue = []
      } = config;

      try {
        const storeData = this.$store.getters[getterName];
        const hasData = Array.isArray(storeData) ? storeData.length > 0 : !!storeData;

        if (!forceReload && hasData) {
          let data = storeData;

          if (transform) {
            data = transform(data);
          }

          if (localProperty) {
            this[localProperty] = data;
          }

          if (onLoaded) {
            onLoaded(data);
          }

          return data;
        }

        await this.$store.dispatch(dispatchName);
        let data = this.$store.getters[getterName] || defaultValue;

        if (transform) {
          data = transform(data);
        }

        if (localProperty) {
          this[localProperty] = data;
        }

        if (onLoaded) {
          onLoaded(data);
        }

        return data;
      } catch (error) {
        console.error(`storeDataLoaderMixin: Error loading ${getterName}:`, error);

        const fallbackValue = defaultValue;
        if (localProperty) {
          this[localProperty] = fallbackValue;
        }

        return fallbackValue;
      }
    },

    async forceLoadStoreData(config) {
      return this.loadStoreData({ ...config, forceReload: true });
    },


    async loadMultipleStoreData(configs) {
      if (!Array.isArray(configs)) {
        console.warn('storeDataLoaderMixin: loadMultipleStoreData requires an array of configs');
        return [];
      }

      const promises = configs.map(config => this.loadStoreData(config));
      return Promise.all(promises);
    }
  }
};

import { PermissionParser } from './parser';

export function permissionIcon(name) {
  if (name.startsWith('settings_')) {
    const settingsIconMap = {
      'settings_edit_any_date': 'fas fa-pen',
      'settings_project_budget_view': 'fas fa-eye',
      'settings_project_files_view': 'fas fa-eye',
      'settings_project_balance_view': 'fas fa-eye',
      'settings_project_contracts_view': 'fas fa-eye',
      'settings_currencies_view': 'fas fa-eye',
      'settings_cash_balance_view': 'fas fa-eye',
      'settings_client_balance_view': 'fas fa-eye',
      'settings_view': 'fas fa-eye',
    };
    return settingsIconMap[name] || 'fas fa-cog';
  }

  const parsed = PermissionParser.parse(name);
  if (!parsed || !parsed.action) {
    return "fas fa-dot-circle";
  }

  switch (parsed.action) {
    case "view":
      return "fas fa-eye";
    case "create":
      return "fas fa-plus";
    case "update":
      return "fas fa-pen";
    case "delete":
      return "fas fa-trash";
    case "export":
      return "fas fa-file-excel";
    default:
      return "fas fa-dot-circle";
  }
}

