const router = createRouter({
  history: createWebHistory(),
  routes,
  scrollBehavior(to, from, savedPosition) {
    if (savedPosition) return savedPosition;
    if (to.hash) return { el: to.hash };
    return { top: 0 };
  },
});

router.beforeEach(async (to, from, next) => {
  const token = TokenUtils.getToken();
  const user = localStorage.getItem("user");

  let userData = null;
  let isSimpleWorker = false;
  let isAdmin = false;

  // Парсим данные пользователя
  try {
    if (user) {
      userData = JSON.parse(user);
      isSimpleWorker =
        userData.roles && userData.roles.includes("basement_worker");
      isAdmin =
        userData.isAdmin === true ||
        (userData.roles && userData.roles.includes("admin"));
    }
  } catch {
    userData = null;
  }

  // Проверка для обычных маршрутов (основная система)
  if (to.meta.requiresAuth) {
    if (!token) {
      return next("/auth/login");
    }
  }

  // Если пользователь пытается попасть на страницу логина, но уже авторизован
  if (to.name === "Login" && token) {
    return next("/");
  }

  if (to.meta.permission) {
    // Проверка прав доступа для всех пользователей (включая simple workers)
    if (
      !store.state.permissionsLoaded ||
      (store.state.permissionsLoaded && store.state.permissions?.length === 0)
    ) {
      await new Promise((resolve) => {
        let attempts = 0;
        const maxAttempts = 100;
        const checkPermissions = () => {
          const hasPermissions =
            store.state.permissionsLoaded &&
            store.state.permissions &&
            store.state.permissions.length > 0;
          if (hasPermissions) {
            resolve();
          } else if (attempts >= maxAttempts) {
            resolve();
          } else {
            attempts++;
            setTimeout(checkPermissions, 50);
          }
        };
        checkPermissions();
      });
    }

    if (to.meta.permission === "mutual_settlements_view") {
      if (store.getters.hasPermission(to.meta.permission)) {
        return next();
      }
      return next({ path: "/" });
    } else {
      if (!store.getters.hasPermission(to.meta.permission)) {
        return next({ path: "/" });
      }
    }
  }

  if (!to.meta.showSearch) {
    store.dispatch("setSearchQuery", "");
  }

  next();
});

export default router;

// src/services/chatRealtime.js
// Encapsulates Laravel Echo subscriptions for chats and presence.

/**
 * @typedef {Object} ChatRealtimeOptions
 * @property {(event:any)=>void} onMessage
 * @property {(event:any)=>void} [onMessageUpdated]
 * @property {(event:any)=>void} [onMessageDeleted]
 * @property {(event:any)=>void} [onReaction]
 * @property {(event:any)=>void} [onPinnedUpdated]
 * @property {(event:any)=>void} [onRead]
 * @property {(event:any)=>void} [onTyping]
 * @property {(error:any)=>void} [onChatError]
 * @property {(users:Array)=>void} [onPresenceHere]
 * @property {(user:Object)=>void} [onPresenceJoining]
 * @property {(user:Object)=>void} [onPresenceLeaving]
 * @property {(error:any)=>void} [onPresenceError]
 * @property {(chatId:number, channelName:string)=>void} [onChannelSubscribed]
 * @property {(msg:string)=>void} [log]
 */

/**
 * @param {any} echo Laravel Echo instance
 * @param {ChatRealtimeOptions} options
 */
export function createChatRealtime(echo, options) {
  const log = options?.log || (() => {});

  /** @type {Map<number, { channel:any, channelName:string, subscribed:boolean }>} */
  const chatChannels = new Map();

  /** @type {string|null} */
  let presenceChannelName = null;
  let presenceChannel = null;
  let presenceSubscribed = false;

  const safeLeave = (name) => {
    if (!name) return;
    try {
      echo.leave(name);
    } catch (_) {
      // ignore
    }
  };

  const subscribeChat = (companyId, chatId) => {
    if (!companyId || !chatId) return;
    const chatIdNum = Number(chatId);
    if (Number.isNaN(chatIdNum)) return;
    if (chatChannels.has(chatIdNum)) {
      // Проверяем, что канал действительно подписан
      const entry = chatChannels.get(chatIdNum);
      if (entry.subscribed) {
        return;
      }
    }

    const channelName = `company.${companyId}.chat.${chatIdNum}`;

    const channel = echo
      .private(channelName)
      .listen(".chat.message.sent", (event) => {
        options?.onMessage?.(event);
      })
      .listen(".chat.message.updated", (event) => {
        options?.onMessageUpdated?.(event);
      })
      .listen(".chat.message.deleted", (event) => {
        options?.onMessageDeleted?.(event);
      })
      .listen(".chat.message.reaction", (event) => {
        options?.onReaction?.(event);
      })
      .listen(".chat.pinned.updated", (event) => {
        options?.onPinnedUpdated?.(event);
      })
      .listen(".chat.read.updated", (event) => {
        options?.onRead?.(event);
      })
      .listen(".chat-typing", (event) => {
        options?.onTyping?.(event);
      })
      .error((error) => {
        log(`[WebSocket] ❌ Ошибка канала ${chatIdNum}:`, error);
        options?.onChatError?.(error);
        // Помечаем как неподписанный при ошибке
        const entry = chatChannels.get(chatIdNum);
        if (entry) {
          entry.subscribed = false;
        }
      });

    // Проверка успешной подписки
    channel.subscribed(() => {
      chatChannels.set(chatIdNum, { channel, channelName, subscribed: true });
      if (options?.onChannelSubscribed) {
        options.onChannelSubscribed(chatIdNum, channelName);
      }
    });

    // Обработка ошибки подписки
    channel.error((error) => {
      log(`[WebSocket] ❌ Ошибка подписки на канал ${chatIdNum}:`, error);
      chatChannels.set(chatIdNum, { channel, channelName, subscribed: false });
      options?.onChatError?.(error);
    });

    // Сохраняем канал даже если еще не подписан
    chatChannels.set(chatIdNum, { channel, channelName, subscribed: false });
  };

  const unsubscribeChat = (chatId) => {
    const chatIdNum = Number(chatId);
    if (Number.isNaN(chatIdNum)) return;

    const entry = chatChannels.get(chatIdNum);
    if (!entry) return;

    try {
      entry.channel?.stopListening?.(".chat.message.sent");
      entry.channel?.stopListening?.(".chat.message.updated");
      entry.channel?.stopListening?.(".chat.message.deleted");
      entry.channel?.stopListening?.(".chat.message.reaction");
      entry.channel?.stopListening?.(".chat.pinned.updated");
      entry.channel?.stopListening?.(".chat.read.updated");
      entry.channel?.stopListening?.(".chat-typing");
    } catch (_) {
      // ignore
    }

    // Echo internal channel names are often prefixed (private-/presence-), so we try a few variants.
    safeLeave(entry.channel?.name);
    safeLeave(entry.channelName);
    safeLeave(`private-${entry.channelName}`);

    chatChannels.delete(chatIdNum);
  };

  const syncChats = (companyId, chats) => {
    if (!companyId) return;
    const ids = new Set(
      (chats || [])
        .filter((c) => c && c.id)
        .map((c) => Number(c.id))
        .filter((id) => !Number.isNaN(id))
    );

    // Unsubscribe removed
    for (const [chatId] of chatChannels.entries()) {
      if (!ids.has(Number(chatId))) {
        unsubscribeChat(chatId);
      }
    }

    // Subscribe new
    ids.forEach((id) => subscribeChat(companyId, id));
  };

  const subscribePresence = (companyId) => {
    if (!companyId) return;
    const channelName = `company.${companyId}.presence`;

    // Re-subscribe if company changed
    if (presenceChannelName && presenceChannelName !== channelName) {
      unsubscribePresence();
    }
    presenceChannelName = channelName;
    presenceSubscribed = false;

    try {
      presenceChannel = echo
        .join(channelName)
        .here((users) => {
          presenceSubscribed = true;
          options?.onPresenceHere?.(users || []);
        })
        .joining((user) => {
          options?.onPresenceJoining?.(user);
        })
        .leaving((user) => {
          options?.onPresenceLeaving?.(user);
        })
        .error((err) => {
          log(`[Presence] ❌ Ошибка presence канала:`, err);
          presenceSubscribed = false;
          options?.onPresenceError?.(err);
        });
    } catch (error) {
      presenceSubscribed = false;
      options?.onPresenceError?.(error);
    }
  };

  const unsubscribePresence = () => {
    if (!presenceChannelName) return;

    safeLeave(presenceChannelName);
    safeLeave(`presence-${presenceChannelName}`);

    presenceChannelName = null;
    presenceChannel = null;
    presenceSubscribed = false;
  };

  const cleanup = () => {
    for (const [chatId] of chatChannels.entries()) {
      unsubscribeChat(chatId);
    }
    chatChannels.clear();
    unsubscribePresence();
  };

  // Методы для проверки состояния
  const isChannelSubscribed = (chatId) => {
    const entry = chatChannels.get(Number(chatId));
    return entry?.subscribed === true;
  };

  const getSubscribedChannels = () => {
    const subscribed = [];
    for (const [chatId, entry] of chatChannels.entries()) {
      if (entry.subscribed) {
        subscribed.push(chatId);
      }
    }
    return subscribed;
  };

  const isPresenceSubscribed = () => {
    return presenceSubscribed;
  };

  const checkAllSubscriptions = () => {
    const pusher = echo.connector?.pusher;
    const connectionState = pusher?.connection?.state || 'unknown';

    const result = {
      echoConnected: connectionState === 'connected',
      echoState: connectionState,
      presenceSubscribed: presenceSubscribed,
      chatChannels: {},
    };

    for (const [chatId, entry] of chatChannels.entries()) {
      result.chatChannels[chatId] = {
        subscribed: entry.subscribed,
        channelName: entry.channelName,
      };
    }

    return result;
  };

  const subscribeToSingleChat = (companyId, chatId) => {
    // Отписываемся от всех других чатов, кроме текущего
    for (const [existingChatId] of chatChannels.entries()) {
      if (Number(existingChatId) !== Number(chatId)) {
        unsubscribeChat(existingChatId);
      }
    }

    // Подписываемся на новый чат
    subscribeChat(companyId, chatId);
  };

  return {
    syncChats,
    subscribePresence,
    unsubscribePresence,
    unsubscribeChat,
    subscribeToSingleChat,
    cleanup,
    getSubscribedChatIds: () => Array.from(chatChannels.keys()),
    // Новые методы для проверки
    isChannelSubscribed,
    getSubscribedChannels,
    isPresenceSubscribed,
    checkAllSubscriptions,
  };
}

// front/src/services/echo.js
import Echo from "laravel-echo";
import Pusher from "pusher-js";
import TokenUtils from "@/utils/tokenUtils";
import { getStore } from "@/store/storeManager";

window.Pusher = Pusher;

// Production = npm run build, Development = npm run dev
const IS_PROD = import.meta.env.PROD;

// Конфигурация WebSocket
const WS_HOST = import.meta.env.VITE_REVERB_HOST || window.location.hostname;
const WS_KEY = import.meta.env.VITE_REVERB_APP_KEY || "hasapchy-key";
const AUTH_URL = `${import.meta.env.VITE_APP_BASE_URL || window.location.origin}/broadcasting/auth`;

// Создаём Echo
const echo = new Echo({
  broadcaster: "reverb",
  key: WS_KEY,
  wsHost: WS_HOST,
  wsPort: IS_PROD ? undefined : 6001,
  wssPort: 443,
  forceTLS: IS_PROD,
  enabledTransports: IS_PROD ? ['wss'] : ['ws', 'wss'],
  authEndpoint: AUTH_URL,

  // Динамическая авторизация - токен берётся при каждом запросе
  authorizer: (channel) => ({
    authorize: (socketId, callback) => {
      const token = TokenUtils.getToken();
      const store = getStore();
      const companyId = store?.getters?.currentCompanyId || "1";

      fetch(AUTH_URL, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Accept': 'application/json',
          'Authorization': token ? `Bearer ${token}` : '',
          'X-Company-ID': companyId.toString(),
        },
        body: JSON.stringify({ socket_id: socketId, channel_name: channel.name }),
      })
        .then(res => {
          if (!res.ok) throw new Error(`Auth failed: ${res.status}`);
          return res.json();
        })
        .then(data => {
          callback(null, data);
        })
        .catch(err => {
          console.error('[Echo] Auth ERROR:', err.message);
          callback(err, null);
        });
    },
  }),
});

// Логи ошибок подключения
const pusher = echo.connector?.pusher;
if (pusher) {
  pusher.connection.bind('unavailable', () => console.error('[Echo] Server unavailable'));
  pusher.connection.bind('failed', () => console.error('[Echo] Connection failed'));
  pusher.connection.bind('error', (err) => {
    if (err?.message?.includes('message port closed')) return;
    console.error('[Echo] Error:', err);
  });
}

export default echo;

// src/services/globalChatRealtime.js
// Глобальный менеджер WebSocket подписок для чатов
// Работает независимо от текущей страницы после авторизации

import echo from "@/services/echo";
import { createChatRealtime } from "@/services/chatRealtime";
import ChatController from "@/api/ChatController";
import { eventBus } from "@/eventBus";

/**
 * Глобальный менеджер WebSocket подписок для чатов
 */
class GlobalChatRealtime {
  constructor() {
    this.realtime = null;
    this.store = null;
    this.onlineUserIds = [];
    this.initialized = false;
    this.connectionCheckInterval = null;
  }

  /**
   * Инициализация глобального сервиса
   * @param {any} store Vuex store
   */
  async initialize(store) {
    if (this.initialized) {
      return;
    }

    this.store = store;

    // Проверяем авторизацию
    const user = store?.state?.user;
    if (!user) {
      return;
    }

    // Проверяем подключение Echo
    if (echo.isConnected && !echo.isConnected()) {
      // Ждем подключения с таймаутом
      const maxAttempts = 10;
      let attempts = 0;
      while (attempts < maxAttempts && echo.isConnected && !echo.isConnected()) {
        await new Promise(resolve => setTimeout(resolve, 500));
        attempts++;
      }
      if (echo.isConnected && !echo.isConnected()) {
        console.error("[GlobalChatRealtime] Не удалось подключиться к Echo");
        return;
      }
    }

    // Создаем экземпляр chatRealtime
    this.realtime = createChatRealtime(echo, {
      onMessage: (event) => {
        eventBus.emit("chat:message", event);
      },
      onMessageUpdated: (event) => {
        eventBus.emit("chat:message:updated", event);
      },
      onMessageDeleted: (event) => {
        eventBus.emit("chat:message:deleted", event);
      },
      onReaction: (event) => {
        eventBus.emit("chat:message:reaction", event);
      },
      onPinnedUpdated: (event) => {
        eventBus.emit("chat:pinned:updated", event);
      },
      onRead: (event) => {
        eventBus.emit("chat:read", event);
      },
      onTyping: (event) => {
        eventBus.emit("chat:typing", event);
      },
      onChatError: (error) => {
        console.error("[GlobalChatRealtime] Ошибка канала:", error);
        eventBus.emit("chat:error", error);
      },
      onChannelSubscribed: (chatId, channelName) => {
        eventBus.emit("chat:subscribed", { chatId, channelName });
      },
      onPresenceHere: (users) => {
        const ids = (users || []).map((u) => Number(u.id)).filter((id) => !Number.isNaN(id));
        this.onlineUserIds = [...ids];
        eventBus.emit("presence:here", users);
      },
      onPresenceJoining: (user) => {
        const id = Number(user?.id);
        if (!Number.isNaN(id) && !this.onlineUserIds.includes(id)) {
          this.onlineUserIds = [...this.onlineUserIds, id];
        }
        eventBus.emit("presence:joining", user);
      },
      onPresenceLeaving: (user) => {
        const id = Number(user?.id);
        if (!Number.isNaN(id)) {
          this.onlineUserIds = this.onlineUserIds.filter((uid) => uid !== id);
        }
        eventBus.emit("presence:leaving", user);
      },
      onPresenceError: (err) => {
        console.error("[GlobalChatRealtime] Ошибка presence:", err);
        eventBus.emit("presence:error", err);
      },
    });

    this.initialized = true;

    // Загружаем чаты и подписываемся
    await this.loadAndSubscribe();

    // Периодическая проверка подключения
    this.connectionCheckInterval = setInterval(() => {
      this.checkConnection();
    }, 30000);
  }

  /**
   * Загрузка чатов и подписка на каналы
   * Важно: чтобы работали уведомления по всем чатам (unread counters),
   * подписываемся на все чаты пользователя.
   */
  async loadAndSubscribe() {
    if (!this.realtime || !this.store) return;

    const companyId = this.store.getters?.currentCompanyId;
    if (!companyId) {
      return;
    }

    try {
      // Загружаем список чатов
      const chats = await ChatController.getChats();
      const chatsArray = Array.isArray(chats) ? chats : [];

      // Находим общий чат
      const generalChat = chatsArray.find((c) => c && c.type === "general") || null;

      // Подписываемся на все чаты
      const allChats = [...chatsArray];
      if (generalChat) {
        allChats.push(generalChat);
      }

      this.realtime.syncChats(companyId, allChats);

      // Подписываемся на presence (онлайн статус)
      this.realtime.subscribePresence(companyId);
    } catch (error) {
      console.error("[GlobalChatRealtime] Ошибка инициализации каналов:", error);
    }
  }

  /**
   * Проверка подключения и переподключение при необходимости
   */
  checkConnection() {
    if (!this.realtime) return;

    const status = this.realtime.checkAllSubscriptions();
    if (!status.echoConnected) {
      // Переподключаемся
      this.reinitialize();
    }
  }

  /**
   * Переинициализация (при смене компании или переподключении)
   */
  async reinitialize() {
    if (!this.store) return;
    await this.loadAndSubscribe();
  }

  /**
   * Синхронизация чатов (вызывается при изменении списка чатов)
   */
  syncChats(chats) {
    if (!this.realtime || !this.store) return;

    const companyId = this.store.getters?.currentCompanyId;
    if (!companyId) return;

    this.realtime.syncChats(companyId, chats);
  }

  /**
   * Подписка на один активный чат (отписывается от всех остальных)
   */
  subscribeToActiveChat(chatId) {
    if (!this.realtime || !this.store) return;

    const companyId = this.store.getters?.currentCompanyId;
    if (!companyId || !chatId) return;

    this.realtime.subscribeToSingleChat(companyId, chatId);
  }

  /**
   * Отписка от чата
   */
  unsubscribeChat(chatId) {
    if (!this.realtime) return;
    this.realtime.unsubscribeChat(chatId);
  }

  /**
   * Получить список онлайн пользователей
   */
  getOnlineUserIds() {
    return [...this.onlineUserIds];
  }

  /**
   * Проверить, онлайн ли пользователь
   */
  isUserOnline(userId) {
    return this.onlineUserIds.includes(Number(userId));
  }

  /**
   * Получить статус всех подписок
   */
  getStatus() {
    if (!this.realtime) return null;
    return this.realtime.checkAllSubscriptions();
  }

  /**
   * Очистка и отключение
   */
  cleanup() {
    if (this.connectionCheckInterval) {
      clearInterval(this.connectionCheckInterval);
      this.connectionCheckInterval = null;
    }

    if (this.realtime) {
      this.realtime.cleanup();
      this.realtime = null;
    }

    this.onlineUserIds = [];
    this.initialized = false;
    this.store = null;
  }
}

